import { n as __exportAll, t as createComponent } from "./compiler_UcH9HwAN.mjs";
import { b as unescapeHTML, m as maybeRenderHead, r as renderComponent, u as renderTemplate } from "./server_cx2YDM1l.mjs";
import { n as site, t as $$BaseLayout } from "./BaseLayout_BNf-BCWt.mjs";
//#region ../../README.md
var html = () => "<h1 id=\"jukette\">jukette</h1>\n<p>A white-label jukebox custom element exposed as <code>&lt;jukette-player&gt;</code>.</p>\n<p>Jukette v0.3.0</p>\n<p>By Rémino Rem<br>\n<a href=\"https://remino.net/\">https://remino.net/</a></p>\n<p><a href=\"https://remino.net/jukette/\">Docs</a> |\n<a href=\"https://github.com/remino/jukette\">Code Repo</a> |\n<a href=\"https://www.npmjs.com/package/jukette\">npm Package</a></p>\n<hr>\n<!-- mtoc-start -->\n<ul>\n<li><a href=\"#installation\">Installation</a>\n<ul>\n<li><a href=\"#html-cdn\">HTML (CDN)</a></li>\n<li><a href=\"#npm\">npm</a></li>\n<li><a href=\"#direct-download\">Direct download</a></li>\n</ul>\n</li>\n<li><a href=\"#usage\">Usage</a></li>\n<li><a href=\"#playlist\">Playlist</a></li>\n<li><a href=\"#tracks\">Tracks</a></li>\n<li><a href=\"#api\">API</a></li>\n<li><a href=\"#styling\">Styling</a></li>\n<li><a href=\"#roadmap\">Roadmap</a></li>\n<li><a href=\"#development\">Development</a></li>\n<li><a href=\"#release\">Release</a></li>\n<li><a href=\"#contributing\">Contributing</a></li>\n<li><a href=\"#licence\">Licence</a></li>\n</ul>\n<!-- mtoc-end -->\n<hr>\n<h2 id=\"installation\">Installation</h2>\n<h3 id=\"html-cdn\">HTML (CDN)</h3>\n<p>Register the custom element automatically from a CDN:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"html\"><code><span class=\"line\"><span style=\"color:#E1E4E8\">&#x3C;</span><span style=\"color:#85E89D\">script</span><span style=\"color:#B392F0\"> src</span><span style=\"color:#E1E4E8\">=</span><span style=\"color:#9ECBFF\">\"https://unpkg.com/jukette\"</span><span style=\"color:#E1E4E8\">>&#x3C;/</span><span style=\"color:#85E89D\">script</span><span style=\"color:#E1E4E8\">></span></span></code></pre>\n<p>Mirrors:</p>\n<ul>\n<li><a href=\"https://unpkg.com/jukette\">https://unpkg.com/jukette</a></li>\n<li><a href=\"https://cdn.jsdelivr.net/npm/jukette\">https://cdn.jsdelivr.net/npm/jukette</a></li>\n</ul>\n<p>Use a pinned version in production:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"html\"><code><span class=\"line\"><span style=\"color:#E1E4E8\">&#x3C;</span><span style=\"color:#85E89D\">script</span><span style=\"color:#B392F0\"> src</span><span style=\"color:#E1E4E8\">=</span><span style=\"color:#9ECBFF\">\"https://unpkg.com/jukette@0.3.0\"</span><span style=\"color:#E1E4E8\">>&#x3C;/</span><span style=\"color:#85E89D\">script</span><span style=\"color:#E1E4E8\">></span></span></code></pre>\n<p>If you want the API instead of auto-registration, import the ES module directly:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"html\"><code><span class=\"line\"><span style=\"color:#E1E4E8\">&#x3C;</span><span style=\"color:#85E89D\">script</span><span style=\"color:#B392F0\"> type</span><span style=\"color:#E1E4E8\">=</span><span style=\"color:#9ECBFF\">\"module\"</span><span style=\"color:#E1E4E8\">></span></span>\n<span class=\"line\"><span style=\"color:#F97583\">	import</span><span style=\"color:#E1E4E8\"> { defineJuketteElement } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> 'https://unpkg.com/jukette@0.3.0/dist/jukette.mjs'</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#B392F0\">	defineJuketteElement</span><span style=\"color:#E1E4E8\">()</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">&#x3C;/</span><span style=\"color:#85E89D\">script</span><span style=\"color:#E1E4E8\">></span></span></code></pre>\n<h3 id=\"npm\">npm</h3>\n<p>Install the convenience package first:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"sh\"><code><span class=\"line\"><span style=\"color:#B392F0\">npm</span><span style=\"color:#9ECBFF\"> install</span><span style=\"color:#9ECBFF\"> jukette</span></span></code></pre>\n<p>Then register the custom element automatically:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"js\"><code><span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#9ECBFF\"> 'jukette/auto'</span></span></code></pre>\n<p>Or import the explicit API:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"js\"><code><span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { defineJuketteElement } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> 'jukette'</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#B392F0\">defineJuketteElement</span><span style=\"color:#E1E4E8\">()</span></span></code></pre>\n<p>TypeScript declarations are included with the package.</p>\n<p>Optional modular packages:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"sh\"><code><span class=\"line\"><span style=\"color:#B392F0\">npm</span><span style=\"color:#9ECBFF\"> install</span><span style=\"color:#9ECBFF\"> jukette</span><span style=\"color:#9ECBFF\"> @remino/jukette-midi</span></span></code></pre>\n<ul>\n<li><code>jukette</code>: convenience package with <code>@remino/jukette-core</code> and\n<code>@remino/jukette-audio</code>.</li>\n<li><code>@remino/jukette-core</code>: backendless player infrastructure.</li>\n<li><code>@remino/jukette-audio</code> and <code>@remino/jukette-audio/auto</code>: browser-native\naudio backend.</li>\n<li><code>@remino/jukette-midi</code> and <code>@remino/jukette-midi/auto</code>: optional MIDI\nbackend.</li>\n</ul>\n<p>Typical addon usage:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"js\"><code><span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#9ECBFF\"> 'jukette/auto'</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#9ECBFF\"> '@remino/jukette-midi/auto'</span></span></code></pre>\n<h3 id=\"direct-download\">Direct download</h3>\n<p>Download the package tarball or individual files from npm/CDN:</p>\n<ul>\n<li><a href=\"https://www.npmjs.com/package/jukette\">https://www.npmjs.com/package/jukette</a></li>\n<li><a href=\"https://unpkg.com/jukette/dist/\">https://unpkg.com/jukette/dist/</a></li>\n<li><a href=\"https://cdn.jsdelivr.net/npm/jukette/dist/\">https://cdn.jsdelivr.net/npm/jukette/dist/</a></li>\n</ul>\n<p>The browser-ready auto-registration file is <code>dist/jukette-auto.min.js</code>.</p>\n<p>Distribution files:</p>\n<ul>\n<li><code>dist/jukette.mjs</code>: ES module library API.</li>\n<li><code>dist/jukette.cjs</code>: CommonJS library API.</li>\n<li><code>dist/jukette-auto.mjs</code>: ES module auto-registration entry.</li>\n<li><code>dist/jukette-auto.cjs</code>: CommonJS auto-registration entry.</li>\n<li><code>dist/jukette-auto.min.js</code>: minified classic browser auto-registration.</li>\n</ul>\n<p><a href=\"#\">Back to top</a></p>\n<hr>\n<h2 id=\"usage\">Usage</h2>\n<p>After registration, use the element with a single source:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"html\"><code><span class=\"line\"><span style=\"color:#E1E4E8\">&#x3C;</span><span style=\"color:#85E89D\">jukette-player</span><span style=\"color:#B392F0\"> src</span><span style=\"color:#E1E4E8\">=</span><span style=\"color:#9ECBFF\">\"/audio/theme.mp3\"</span><span style=\"color:#E1E4E8\">>&#x3C;/</span><span style=\"color:#85E89D\">jukette-player</span><span style=\"color:#E1E4E8\">></span></span></code></pre>\n<p>Or pass a playlist with child track elements:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"html\"><code><span class=\"line\"><span style=\"color:#E1E4E8\">&#x3C;</span><span style=\"color:#85E89D\">jukette-player</span><span style=\"color:#B392F0\"> preload-metadata</span><span style=\"color:#B392F0\"> prefer-media-metadata</span><span style=\"color:#E1E4E8\">></span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">	&#x3C;</span><span style=\"color:#85E89D\">jukette-track</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">		title</span><span style=\"color:#E1E4E8\">=</span><span style=\"color:#9ECBFF\">\"Theme\"</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">		artist</span><span style=\"color:#E1E4E8\">=</span><span style=\"color:#9ECBFF\">\"Local\"</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">		src</span><span style=\"color:#E1E4E8\">=</span><span style=\"color:#9ECBFF\">\"/audio/theme.mp3\"</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">	>&#x3C;/</span><span style=\"color:#85E89D\">jukette-track</span><span style=\"color:#E1E4E8\">></span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">	&#x3C;</span><span style=\"color:#85E89D\">jukette-track</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">		title</span><span style=\"color:#E1E4E8\">=</span><span style=\"color:#9ECBFF\">\"Sketch\"</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">		src</span><span style=\"color:#E1E4E8\">=</span><span style=\"color:#9ECBFF\">\"/midi/sketch.mid\"</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">		type</span><span style=\"color:#E1E4E8\">=</span><span style=\"color:#9ECBFF\">\"midi\"</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">	>&#x3C;/</span><span style=\"color:#85E89D\">jukette-track</span><span style=\"color:#E1E4E8\">></span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">	&#x3C;</span><span style=\"color:#85E89D\">jukette-track</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">		title</span><span style=\"color:#E1E4E8\">=</span><span style=\"color:#9ECBFF\">\"Reprise\"</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">		artist</span><span style=\"color:#E1E4E8\">=</span><span style=\"color:#9ECBFF\">\"Local\"</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">		src</span><span style=\"color:#E1E4E8\">=</span><span style=\"color:#9ECBFF\">\"/audio/reprise.ogg\"</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">	>&#x3C;/</span><span style=\"color:#85E89D\">jukette-track</span><span style=\"color:#E1E4E8\">></span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">&#x3C;/</span><span style=\"color:#85E89D\">jukette-player</span><span style=\"color:#E1E4E8\">></span></span></code></pre>\n<p>Changing the selected track prepares it for playback but does not start it\nautomatically. Jukette enables play, seek, and time controls once the selected\ntrack is ready.</p>\n<p>The default <code>jukette</code> entry includes browser-native audio support only. Import\naddons for other track types:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"js\"><code><span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#9ECBFF\"> 'jukette/auto'</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#9ECBFF\"> '@remino/jukette-midi/auto'</span></span></code></pre>\n<p><a href=\"#\">Back to top</a></p>\n<hr>\n<h2 id=\"playlist\">Playlist</h2>\n<p>Use direct <code>&lt;jukette-track&gt;</code> children for authored HTML. Browser HTML requires\nexplicit closing tags, so write <code>&lt;jukette-track&gt;&lt;/jukette-track&gt;</code> rather than a\nself-closing tag.</p>\n<p>For generated markup or compatibility with older usage, the <code>playlist</code>\nattribute also accepts JSON. Each item can be either a URL string or a track\nobject.</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"json\"><code><span class=\"line\"><span style=\"color:#E1E4E8\">[</span></span>\n<span class=\"line\"><span style=\"color:#9ECBFF\">	\"/audio/one.mp3\"</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">	{</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">		\"title\"</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"Two\"</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">		\"artist\"</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"Example\"</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">		\"src\"</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"/audio/two.ogg\"</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">		\"type\"</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#9ECBFF\">\"audio\"</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">		\"preload\"</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">true</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">		\"preferMediaMetadata\"</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">false</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">	}</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">]</span></span></code></pre>\n<p>When JSON parsing fails, Jukette treats the attribute as a newline-separated URL\nlist.</p>\n<p>Track sources are resolved in this order:</p>\n<ul>\n<li><code>player.playlist</code> set from JavaScript.</li>\n<li>Direct <code>&lt;jukette-track&gt;</code> children.</li>\n<li><code>playlist</code> attribute JSON or newline list.</li>\n<li>Single <code>src</code> attribute.</li>\n</ul>\n<p><a href=\"#\">Back to top</a></p>\n<hr>\n<h2 id=\"tracks\">Tracks</h2>\n<p><code>&lt;jukette-track&gt;</code> attributes and track object fields:</p>\n<ul>\n<li><code>src</code>: required URL for a local audio file or local MIDI file.</li>\n<li><code>title</code>: optional display title.</li>\n<li><code>artist</code>: optional display artist.</li>\n<li><code>type</code>: optional backend-owned track type such as <code>audio</code>, <code>midi</code>, or\n<code>soundcloud</code>.</li>\n<li><code>preload</code> attribute / <code>preload</code> object field: optional per-track playback\npreparation preference.</li>\n<li><code>prefer-media-metadata</code> / <code>preferMediaMetadata</code>: optional per-track override\nfor the player’s media metadata preference.</li>\n</ul>\n<p>If <code>type</code> is omitted, Jukette infers <code>.mid</code> / <code>.midi</code> files. Everything else\nfalls back to browser-native audio when the audio backend is registered.</p>\n<p>MIDI playback uses <code>@tonejs/midi</code> for parsing and a compact Tone.js synth for\nbrowser playback. It is intentionally simple and suitable for local MIDI\npreviews, not a full General MIDI instrument set.</p>\n<p>If a selected track type has no registered backend, Jukette leaves the track\nselected, keeps playback controls disabled, and surfaces that the track type is\nunavailable.</p>\n<p><a href=\"#\">Back to top</a></p>\n<hr>\n<h2 id=\"api\">API</h2>\n<p>Each element exposes:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"js\"><code><span class=\"line\"><span style=\"color:#F97583\">const</span><span style=\"color:#79B8FF\"> player</span><span style=\"color:#F97583\"> =</span><span style=\"color:#E1E4E8\"> document.</span><span style=\"color:#B392F0\">querySelector</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#9ECBFF\">'jukette-player'</span><span style=\"color:#E1E4E8\">)</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">player.</span><span style=\"color:#B392F0\">play</span><span style=\"color:#E1E4E8\">()</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">player.</span><span style=\"color:#B392F0\">pause</span><span style=\"color:#E1E4E8\">()</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">player.</span><span style=\"color:#B392F0\">toggle</span><span style=\"color:#E1E4E8\">()</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">player.</span><span style=\"color:#B392F0\">seek</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#79B8FF\">30</span><span style=\"color:#E1E4E8\">)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">player.currentTime </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 30</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">console.</span><span style=\"color:#B392F0\">log</span><span style=\"color:#E1E4E8\">(player.currentTime)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">console.</span><span style=\"color:#B392F0\">log</span><span style=\"color:#E1E4E8\">(player.currentTrack)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">console.</span><span style=\"color:#B392F0\">log</span><span style=\"color:#E1E4E8\">(player.currentTrackIndex)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">console.</span><span style=\"color:#B392F0\">log</span><span style=\"color:#E1E4E8\">(player.totalTracks)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">player.playlist </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> [{ title: </span><span style=\"color:#9ECBFF\">'Track'</span><span style=\"color:#E1E4E8\">, src: </span><span style=\"color:#9ECBFF\">'/track.mp3'</span><span style=\"color:#E1E4E8\"> }]</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">player.preloadMetadata </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> true</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">player.preferMediaMetadata </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> true</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">player.midiOscillator </span><span style=\"color:#F97583\">=</span><span style=\"color:#9ECBFF\"> 'sine'</span></span></code></pre>\n<p>Core and addon imports:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"js\"><code><span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { defineJuketteElement } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> '@remino/jukette-core'</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { registerJuketteAudioBackend } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> '@remino/jukette-audio'</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">import</span><span style=\"color:#E1E4E8\"> { registerJuketteMidiBackend } </span><span style=\"color:#F97583\">from</span><span style=\"color:#9ECBFF\"> '@remino/jukette-midi'</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#B392F0\">registerJuketteAudioBackend</span><span style=\"color:#E1E4E8\">()</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">registerJuketteMidiBackend</span><span style=\"color:#E1E4E8\">()</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">defineJuketteElement</span><span style=\"color:#E1E4E8\">()</span></span></code></pre>\n<p>Use the <code>preload-metadata</code> attribute or <code>preloadMetadata</code> property to discover\nplaylist durations before tracks are played. Jukette preloads metadata for\nregistered backends that provide preload hooks, including browser-native audio\nand local MIDI.</p>\n<p>Use <code>currentTime</code> to read the current playback position in seconds. Assigning\nto <code>currentTime</code> seeks, matching native media element behavior.</p>\n<p>Use <code>currentTrack</code>, <code>currentTrackIndex</code>, and <code>totalTracks</code> to inspect the track\nselection state.</p>\n<p>Selecting a track prepares it and resets playback to the start of that track.\nPlayback begins only after an explicit <code>play()</code> call or a user press on the\nplay button.</p>\n<p>If the selected track backend is unavailable, Jukette keeps the selected track\nvisible but leaves play, seek, and time controls disabled.</p>\n<p>Use <code>prefer-media-metadata</code> or <code>preferMediaMetadata</code> to let readable media-file\ntags override authored track titles and artists. Jukette currently reads MP3\nID3 <code>TIT2</code> title and <code>TPE1</code> artist tags, plus MIDI track/sequence names as\ntitles. MIDI artists stay authored-only. Authored values stay in place when\ntags are missing, unreadable, or unsupported.</p>\n<p>Direct <code>&lt;jukette-track&gt;</code> children and JavaScript track objects can override the\nplayer-level preference per track. Use <code>prefer-media-metadata</code> or\n<code>preferMediaMetadata: true</code> to force metadata display for that track, use\n<code>prefer-media-metadata=\"false\"</code> or <code>preferMediaMetadata: false</code> to force\nauthored display values, or omit it to inherit the player setting.</p>\n<p>Use <code>preload</code> or <code>preload: true</code> to ask Jukette to prepare a track for playback\nwhen possible. The flag is track-local and does not change media metadata\npreloading.</p>\n<p>Use <code>midi-oscillator</code> or <code>midiOscillator</code> to choose the Tone.js MIDI preview\noscillator. Supported values are <code>auto</code>, <code>sine</code>, <code>square</code>, <code>sawtooth</code>, and\n<code>triangle</code>. <code>auto</code> is the default and maps MIDI program changes to a simple\npreview timbre; invalid values fall back to <code>auto</code>. The property matters only\nwhen the MIDI addon is registered.</p>\n<p>Jukette dispatches bubbling composed custom events from the <code>&lt;jukette-player&gt;</code>\nhost:</p>\n<ul>\n<li><code>jukette:play</code></li>\n<li><code>jukette:pause</code></li>\n<li><code>jukette:seek</code></li>\n<li><code>jukette:ended</code></li>\n<li><code>jukette:trackchange</code></li>\n</ul>\n<p>Each event includes <code>event.detail</code> with the current <code>track</code>, <code>tracks</code>, <code>index</code>,\n<code>type</code>, <code>currentTime</code>, <code>duration</code>, and <code>playing</code>.</p>\n<p><a href=\"#\">Back to top</a></p>\n<hr>\n<h2 id=\"styling\">Styling</h2>\n<p>Jukette keeps the default UI basic on purpose. It uses inherited text color and\nfont, a single border, and native range controls. Style the host element first:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"css\"><code><span class=\"line\"><span style=\"color:#85E89D\">jukette-player</span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">	color</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">#111</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">	font</span><span style=\"color:#E1E4E8\">:</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">		1</span><span style=\"color:#F97583\">rem</span><span style=\"color:#E1E4E8\">/</span><span style=\"color:#79B8FF\">1.4</span><span style=\"color:#79B8FF\"> system-ui</span><span style=\"color:#E1E4E8\">,</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">		sans-serif</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">	max-inline-size</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">36</span><span style=\"color:#F97583\">rem</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#FFAB70\">	--jukette-control-size</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">2.25</span><span style=\"color:#F97583\">rem</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span></code></pre>\n<p>The host supports these stable styling inputs:</p>\n<ul>\n<li><code>color</code>: inherited by text, borders, buttons, and range accents.</li>\n<li><code>font</code>: inherited by labels, buttons, and the track selector.</li>\n<li><code>--jukette-control-size</code>: controls the square play button size. Defaults to\n<code>2em</code>.</li>\n<li><code>inline-size</code>, <code>max-inline-size</code>, <code>margin</code>, and other normal layout\nproperties on <code>jukette-player</code>.</li>\n</ul>\n<p>Use host attributes for state-specific styling:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"css\"><code><span class=\"line\"><span style=\"color:#85E89D\">jukette-player</span><span style=\"color:#E1E4E8\">[</span><span style=\"color:#B392F0\">data-kind</span><span style=\"color:#F97583\">=</span><span style=\"color:#9ECBFF\">'midi'</span><span style=\"color:#E1E4E8\">] {</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">	color</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">#164e63</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span></code></pre>\n<p>Range inputs use <code>accent-color: currentColor</code> inside the shadow DOM, so changing\nthe host <code>color</code> changes the seek accent in browsers that support native range\naccent styling.</p>\n<p>For deeper styling, Jukette exposes stable <code>::part()</code> hooks:</p>\n<ul>\n<li>Layout: <code>player</code>, <code>track</code>, <code>seek</code>, <code>time</code>, <code>controls</code>.</li>\n<li>Track display: <code>title</code>, <code>artist</code>, <code>status</code>.</li>\n<li>Controls: <code>button</code>, <code>play-button</code>, <code>seek-input</code>, <code>track-select</code>.</li>\n</ul>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"css\"><code><span class=\"line\"><span style=\"color:#85E89D\">jukette-player</span><span style=\"color:#E1E4E8\">::part(player) {</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">	border</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">0</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">	padding</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">0</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#85E89D\">jukette-player</span><span style=\"color:#E1E4E8\">::part(</span><span style=\"color:#85E89D\">play-button</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">	border-radius</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">999</span><span style=\"color:#F97583\">px</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#85E89D\">jukette-player</span><span style=\"color:#E1E4E8\">::part(</span><span style=\"color:#85E89D\">track-select</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#79B8FF\">	font-size</span><span style=\"color:#E1E4E8\">: </span><span style=\"color:#79B8FF\">0.95</span><span style=\"color:#F97583\">rem</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span></code></pre>\n<p><a href=\"#\">Back to top</a></p>\n<hr>\n<h2 id=\"roadmap\">Roadmap</h2>\n<p>Forward-looking work lives in <a href=\"./ROADMAP.md\">ROADMAP.md</a>. For now, that covers\nthe planned SoundCloud addon direction without expanding <code>jukette</code> core again.</p>\n<p><a href=\"#\">Back to top</a></p>\n<hr>\n<h2 id=\"development\">Development</h2>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"sh\"><code><span class=\"line\"><span style=\"color:#B392F0\">npm</span><span style=\"color:#9ECBFF\"> install</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">npm</span><span style=\"color:#9ECBFF\"> run</span><span style=\"color:#9ECBFF\"> dev</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">npm</span><span style=\"color:#9ECBFF\"> run</span><span style=\"color:#9ECBFF\"> build</span></span></code></pre>\n<p>This repository is an npm workspaces monorepo:</p>\n<ul>\n<li><code>packages/jukette</code>: publishes <code>jukette</code>.</li>\n<li><code>packages/core</code>: publishes <code>@remino/jukette-core</code>.</li>\n<li><code>packages/audio</code>: publishes <code>@remino/jukette-audio</code>.</li>\n<li><code>packages/midi</code>: publishes <code>@remino/jukette-midi</code>.</li>\n<li><code>apps/docs</code>: Astro docs and demo site.</li>\n</ul>\n<p>Root scripts orchestrate builds in dependency order. Use <code>npm run build</code>,\n<code>npm run typecheck</code>, and <code>npm test</code> from the repo root.</p>\n<p>Common root shortcuts:</p>\n<ul>\n<li><code>npm run dev</code> or <code>npm run dev:docs</code>: start the Astro docs site.</li>\n<li><code>npm run build:packages</code>: build the publishable packages only.</li>\n<li><code>npm run build:docs</code>: build the docs app only.</li>\n<li><code>npm run preview:docs</code>: preview the built docs app.</li>\n</ul>\n<p><a href=\"#\">Back to top</a></p>\n<hr>\n<h2 id=\"release\">Release</h2>\n<p>Release automation is available through <code>release-it</code>. A release runs checks,\nbumps the root and publishable workspace package versions in lockstep, builds\nthe workspace packages, dry-runs publish order, publishes the scoped packages\nfirst, publishes <code>jukette</code> last, creates the GitHub release, and then publishes\ndocs:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"sh\"><code><span class=\"line\"><span style=\"color:#B392F0\">npm</span><span style=\"color:#9ECBFF\"> run</span><span style=\"color:#9ECBFF\"> release:dry-run</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">npm</span><span style=\"color:#9ECBFF\"> run</span><span style=\"color:#9ECBFF\"> release</span></span></code></pre>\n<p>If docs publishing fails after the package release, rerun it directly:</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"sh\"><code><span class=\"line\"><span style=\"color:#B392F0\">npm</span><span style=\"color:#9ECBFF\"> run</span><span style=\"color:#9ECBFF\"> docs:publish</span></span></code></pre>\n<p>Before running a real release, make sure <code>RELEASE_IT_GITHUB_TOKEN</code> is set and\n<code>npm whoami --registry https://registry.npmjs.org/</code> passes. Release-it prompts\nfor an npm OTP when npm requires one.</p>\n<p><a href=\"#\">Back to top</a></p>\n<hr>\n<h2 id=\"contributing\">Contributing</h2>\n<ol>\n<li>Fork the repository.</li>\n<li>Create a feature branch: <code>git checkout -b feature/amazing-feature</code>.</li>\n<li>Make your changes.</li>\n<li>Run <code>npm run build</code> and <code>npm test</code>.</li>\n<li>Commit, push, and open a pull request.</li>\n</ol>\n<hr>\n<h2 id=\"licence\">Licence</h2>\n<p>ISC. See <a href=\"LICENSE.md\">LICENSE.md</a>.</p>\n";
